INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-10ced7e2-moex-00266', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '地方制度法中，有關於山地鄉之鄉長，因辭職、去職、死亡、停職等原因出缺時的規範，下列敘述何 者正確？', '["由原住民族委員會派員代理", "自事實發生之日起6個月內完成補選。但所遺任期不足2年者，不再補選，由代理人代理至該屆任 期屆滿為止", "代理人不得為被代理者之配偶、前配偶、四親等內之血親、三親等內之姻親關係", "山地鄉鄉長以山地原住民為限，但因辭職、去職、死亡、停職等原因出缺時之代理人，不受此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00267', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '根據諮商取得原住民族部落同意參與辦法第4條，原住民族基本法第21條所稱原住民族或部落同意， 指過半數關係部落依本辦法召開部落會議議決通過；所稱原住民族或部落參與，指過半數關係部落依 本辦法召開部落會議議決通過之參與機制。下列關於「關係部落」的說明，何者正確？', '["關係部落，是指和同意事項發生所在地部落，具血緣以及地緣相關性之部落", "關係部落由同意事項所在地之鄉（鎮、市、區）公所認定之；認定有困難時，應敘明爭議事項及處 理意見，報請中央原住民族主管機關認定", "關係部落之部落會議主席自收受同意事項之通知，逾二個月未召集部落會議時，申請人得自行代行 召集", "關係部落得聯合召集部落會議議決同意事項。前項部落會議，由關係部落之各部落會議主席共同主持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00268', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '原住民族文化資產處理辦法中，有關於原住民族無形文化資產、文化資產保存技術之登錄及保存者之 認定程序的規範，不包含下列那一個項目？', '["會同原住民族主管機關，並邀請所屬原住民族、部落或其他傳統組織及利益團體，進行現場勘查。 但無法知悉所屬部落或其他傳統組織及利益團體者，不在此限", "辦理公聽會、說明會或其他適當方式諮商相關原住民族、部落或其他傳統組織", "經主管機關召開原住民族文化資產審議會審議通過後，作成指定或登錄處分，辦理公告，並通知申 請人或處分相對人", "直轄市、縣（市）主管機關指定或登錄後，應報中央主管機關核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00269', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '原住民族傳統智慧創作保護條例，乃是為促進原住民族文化發展，依原住民族基本法第13條之規定 所制定。其對智慧創作專用權之規範，不包含下列那一項？', '["智慧創作專用權，指智慧創作財產權及智慧創作人格權", "智慧創作專用權人享有下列智慧創作人格權，包括專有禁止他人以歪曲、割裂、竄改或其他方法改 變其智慧創作之內容、形式或名目致損害其名譽之創作人格權", "智慧創作專用權依規定為原住民族或部落取得者，其智慧創作之收入，應以原住民族或部落利益為 目的，設立共同基金", "智慧創作專用權不得為讓與、設定質權及作為為強制執行之標的，但經主管機關同意者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00270', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '根據山坡地保育利用條例第37條，原住民取得原住民保留地所有權，如有移轉，以原住民為限，但 有特定情形者，得由政府承受私有原住民保留地，下列何者屬於得由政府承受私有原住民保留地之特 定情形？', '["興辦依土地徵收條例第3條（因公益需要之徵收）、第4條第1項（區段徵收）規定之各款事業及 所有權人依該條例第8條規定申請一併徵收", "經中央原住民族主管機關審認符合轉換作為傳統領域土地之需求", "稅捐稽徵機關受理以原住民保留地抵繳增值稅", "因私法金錢給付義務之執行事件未能拍定原住民保留地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00271', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '原住民保留地經劃定為禁伐區域，其具原住民身分之所有權人或合法使用權人，得申請禁伐補償。下 列那一項非屬由主管機關將原住民保留地劃定為禁伐區域並公告之條件？', '["依法編定為林業用地或適用林業用地管制", "依法劃設為保護區或水源特定區", "依法劃設為原住民特定區域計畫範圍", "依法劃設為國家公園之區域"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00272', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依照原住民族語言發展法，首次將原住民族語言列為國家語言，下列何者不是此法案的立法目的？', '["為實現歷史正義", "推動原住民族自治", "促進原住民族語言之保存與發展", "保障原住民族語言之使用及傳承"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00273', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '因為下列那一個法規立法，最近許多原住民族族人都在直轄市、縣（市）主管機關轄下被聘用擔任專 職族語老師，傳承族語文化？', '["原住民族教育法", "國家語言發展法", "原住民族語言發展法", "通用語言文字法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00274', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '國家語言發展法和原住民族的語言保存與發展息息相關，下列關於國家語言發展法的敘述，何者錯誤？', '["學校教育得使用各國家語言為之", "本法所稱國家語言，指臺灣各固有族群使用之自然語言，但不包含手語", "國民參與政府機關（構）行政、立法及司法程序時，得使用其選擇之國家語言", "政府機關（構）應於必要時提供各國家語言間之通譯服務，並積極培育各國家語言通譯人才"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00275', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '根據原住民族基本法，下列那一項目前不是原住民族在原住民族地區及經中央原住民族主管機關公告 之海域依法可從事的非營利行為？', '["獵捕野生動物及採集野生植物及菌類", "採取礦物、土石", "使用空拍機監測公告海域漁類", "利用水資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL)
